{
  "mode": "io",
  "tests": [
    {
      "name": "test_no_scroll_logged_out",
      "input": "GET /activity-feed",
      "output": "200 OK\n{\"scrolling\": false}",
      "notes": "Validates that the activity feed does not allow perpetual scrolling when logged out."
    },
    {
      "name": "test_activity_feed_content",
      "input": "GET /activity-feed",
      "output": "200 OK\n{\"activities\": [{\"id\": 1, \"title\": \"Challenge 1\"}, {\"id\": 2, \"title\": \"Challenge 2\"}]}",
      "notes": "Checks that the activity feed returns content correctly when logged out."
    },
    {
      "name": "test_no_scroll_with_large_data",
      "input": "GET /activity-feed?page=1000",
      "output": "200 OK\n{\"scrolling\": false}",
      "notes": "Tests that even with a large page request, perpetual scrolling is disabled."
    },
    {
      "name": "test_empty_activity_feed",
      "input": "GET /activity-feed?page=1",
      "output": "200 OK\n{\"activities\": []}",
      "notes": "Ensures that an empty activity feed is handled correctly without scrolling."
    },
    {
      "name": "test_invalid_page_request",
      "input": "GET /activity-feed?page=invalid",
      "output": "400 Bad Request\n{\"error\": \"Invalid page number\"}",
      "notes": "Tests response to an invalid page request, ensuring no scrolling occurs."
    },
    {
      "name": "test_activity_feed_format",
      "input": "GET /activity-feed",
      "output": "200 OK\n{\"activities\": [{\"id\": 1, \"title\": \"Challenge 1\"}]}",
      "notes": "Validates that the activity feed returns data in the correct JSON format."
    },
    {
      "name": "test_rate_limiting",
      "input": "GET /activity-feed",
      "output": "429 Too Many Requests\n{\"error\": \"Rate limit exceeded\"}",
      "notes": "Checks that rate limiting is enforced and scrolling is disabled."
    },
    {
      "name": "test_authentication_required",
      "input": "GET /activity-feed",
      "output": "401 Unauthorized\n{\"error\": \"Authentication required\"}",
      "notes": "Ensures that unauthenticated users are correctly handled without scrolling."
    }
  ],
  "assumptions": "The application is deployed and accessible at the specified endpoints.",
  "notes": "Ensure that the application is running in a state where these endpoints can be tested."
}
